#include <stdio.h>
int max(int a, int b) { return a > b ? a : b; }
int min(int a, int b) { return a < b ? a : b; }
int dp[100005][2];
int getAns(int* Arr, int ind, int buy, int n, int fee) {
    if (ind == n) return 0;
    if (dp[ind][buy] != -1) return dp[ind][buy];
    int profit;
    if (buy == 0) profit = max(0 + getAns(Arr, ind + 1, 0, n, fee), -Arr[ind] + getAns(Arr, ind + 1, 1, n, fee));
    if (buy == 1) profit = max(0 + getAns(Arr, ind + 1, 1, n, fee), Arr[ind] - fee + getAns(Arr, ind + 1, 0, n, fee));
    return dp[ind][buy] = profit;
}
int maximumProfit(int n, int fee, int* Arr) {
    for (int i = 0; i < n; i++) for (int j = 0; j < 2; j++) dp[i][j] = -1;
    if (n == 0) return 0;
    return getAns(Arr, 0, 0, n, fee);
}
