import java.util.*;
public class Solution {
    public int getAns(int[] Arr, int ind, int buy, int n, int fee, int[][] dp) {
        if (ind == n) return 0;
        if (dp[ind][buy] != -1) return dp[ind][buy];
        int profit;
        if (buy == 0) profit = Math.max(0 + getAns(Arr, ind + 1, 0, n, fee, dp), -Arr[ind] + getAns(Arr, ind + 1, 1, n, fee, dp));
        if (buy == 1) profit = Math.max(0 + getAns(Arr, ind + 1, 1, n, fee, dp), Arr[ind] - fee + getAns(Arr, ind + 1, 0, n, fee, dp));
        return dp[ind][buy] = profit;
    }
    public int maximumProfit(int n, int fee, int[] Arr) {
        int[][] dp = new int[n][2];
        for (int i = 0; i < n; i++) for (int j = 0; j < 2; j++) dp[i][j] = -1;
        if (n == 0) return 0;
        return getAns(Arr, 0, 0, n, fee, dp);
    }
